/**
 * Menghapus data ATP berdasarkan ID.
 */
function deleteATP(params) {
  return deleteData('ATP_Data', params.id);
}

/**
 * Menghapus data KKTP berdasarkan ID spesifik.
 */
function deleteKKTP(params) {
  return deleteData('KKTP_Data', params.id);
}

/**
 * Menghapus semua KKTP yang terkait dengan ID ATP tertentu.
 * Penting untuk menjaga kebersihan data saat ATP dihapus.
 */
function deleteKKTPsByATPId(params) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName('KKTP_Data');
  if (!sheet) return responseError('Sheet KKTP_Data tidak ditemukan.');

  const data = sheet.getDataRange().getValues();
  const atpIdToDelete = String(params.atpId);
  let deletedCount = 0;

  // Loop dari bawah ke atas agar aman saat menghapus baris
  for (let i = data.length - 1; i >= 1; i--) {
    // Asumsi kolom ke-2 (index 1) adalah atpId. Sesuaikan jika urutan kolom Anda berbeda.
    if (String(data[i][1]) === atpIdToDelete) { 
      sheet.deleteRow(i + 1);
      deletedCount++;
    }
  }

  return responseSuccess({ deleted: deletedCount });
}

// Pastikan fungsi deleteData (helper) Anda sudah mendukung penghapusan baris.
// Jika belum, gunakan fungsi standar ini:
function deleteData(sheetName, id) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(sheetName);
  if (!sheet) return responseError("Sheet " + sheetName + " tidak ditemukan.");

  const data = sheet.getDataRange().getValues();
  for (let i = 0; i < data.length; i++) {
    // Asumsi kolom pertama (index 0) adalah ID
    if (String(data[i][0]) === String(id)) {
      sheet.deleteRow(i + 1);
      return responseSuccess({ message: "Data berhasil dihapus." });
    }
  }
  return responseError("ID tidak ditemukan.");
}
