    if (!e || !e.parameter) {
      throw new Error("Struktur permintaan tidak valid atau parameter tidak ditemukan. Pastikan permintaan dikirim dengan benar.");
    }

    const action = e.parameter.action;
    // **FIX 2: Pemeriksaan eksplisit untuk keberadaan 'action'**
    if (!action) {
      throw new Error("Parameter 'action' wajib ada dalam permintaan.");
    }

    // **FIX 3: Parsing JSON yang lebih aman dengan blok try-catch sendiri**
    let params = {};
    if (e.parameter.params) {
      try {
        // Hanya parse jika params bukan string kosong
        if (e.parameter.params.trim() !== "") {
          params = JSON.parse(e.parameter.params);
        }
      } catch (parseError) {
        // Memberikan error yang lebih spesifik jika JSON tidak valid
        throw new Error(`Gagal mem-parsing parameter JSON. Pastikan formatnya benar. Error: ${parseError.message}`);
      }
    }

    // Peta aksi untuk memanggil fungsi yang sesuai
    const ACTION_MAP = {
      // TP Actions
      'getTPsBySubject': getTPsBySubject,
      'saveTP': saveTP,
      'updateTP': updateTP,
      'deleteTP': deleteTP,
      // ATP Actions
      'getATPsByTPId': getATPsByTPId,
      'saveATP': saveATP,
      'updateATP': updateATP,
      'deleteATP': deleteATP,
      'deleteATPsByTPId': deleteATPsByTPId,
      // PROTA Actions
      'getPROTAsByTPId': getPROTAsByTPId,
      'savePROTA': savePROTA,
      'updatePROTA': updatePROTA,
      'deletePROTA': deletePROTA,
      'deletePROTAsByTPId': deletePROTAsByTPId,
      // KKTP Actions
