      'saveKKTP': saveKKTP,
      'deleteKKTPsByATPId': deleteKKTPsByATPId,
      'deleteKKTPsByTPId': deleteKKTPsByTPId,
      // PROSEM Actions
      'getPROSEMsByPROTAId': getPROSEMsByPROTAId,
      'savePROSEM': savePROSEM,
      'deletePROSEMsByPROTAId': deletePROSEMsByPROTAId,
      'deletePROSEMsByTPId': deletePROSEMsByTPId,
      // Gemini AI Actions
      'generateTPs': (p) => callGeminiAPI(p, 'generateTPs'),
      'generateATP': (p) => callGeminiAPI(p, 'generateATP'),
      'generatePROTA': (p) => callGeminiAPI(p, 'generatePROTA'),
      'generateKKTP': (p) => callGeminiAPI(p, 'generateKKTP'),
      'generatePROSEM': (p) => callGeminiAPI(p, 'generatePROSEM'),
    };

    if (ACTION_MAP[action]) {
      const result = ACTION_MAP[action](params);
      return createSuccessResponse(result);
    } else {
      throw new Error(`Aksi tidak dikenal: '${action}'`);
    }

  } catch (error) {
    // **FIX 4: Logging yang lebih informatif untuk debugging**
