function saveData(sheetName, data) {
    const sheet = getSheet(sheetName);
    const { headers } = getSheetData(sheet);
    if (headers.length === 0) {
      const keys = Object.keys(data);
      sheet.appendRow(keys);
      keys.forEach(k => headers.push(k));
    }
    data.id = data.id || Utilities.getUuid();
    data.createdAt = data.createdAt || new Date().toISOString();
    if (sheetName === 'TP_Data') {
      data.updatedAt = new Date().toISOString();
    }
    const newRow = objectToRowArray(headers, data);
    sheet.appendRow(newRow);
    return data;
}

function updateData(sheetName, id, dataToUpdate) {
    const sheet = getSheet(sheetName);
    const { headers } = getSheetData(sheet);
    const rowIndex = findRowIndex(sheet, headers, 'id', id);
    if (rowIndex === -1) throw new Error(`Data dengan ID ${id} tidak ditemukan di sheet ${sheetName}.`);

    const existingRowValues = sheet.getRange(rowIndex, 1, 1, headers.length).getValues()[0];
    const existingData = rowsToObjects(headers, [existingRowValues])[0];

    if (sheetName === 'TP_Data') {
        dataToUpdate.updatedAt = new Date().toISOString();
    }

    const updatedData = { ...existingData, ...dataToUpdate };
    const updatedRow = objectToRowArray(headers, updatedData);
    sheet.getRange(rowIndex, 1, 1, headers.length).setValues([updatedRow]);
    return updatedData;
}

function deleteData(sheetName, id) {
    const sheet = getSheet(sheetName);
    const { headers } = getSheetData(sheet);
    const rowIndex = findRowIndex(sheet, headers, 'id', id);
    if (rowIndex !== -1) {
        sheet.deleteRow(rowIndex);
        return { success: true };
    }
    return { success: false, message: `Data dengan ID ${id} tidak ditemukan.` };
}

function deleteDataByForeignKey(sheetName, foreignKeyColumn, foreignKeyValue) {
    const sheet = getSheet(sheetName);
    const { headers, rows } = getSheetData(sheet);
    const keyIndex = headers.indexOf(foreignKeyColumn);
    if (keyIndex === -1 || rows.length === 0) return { success: true, rowsDeleted: 0 };

    let rowsDeleted = 0;
    for (let i = rows.length - 1; i >= 0; i--) {
        if (rows[i][keyIndex] == foreignKeyValue) {
            sheet.deleteRow(i + 2);
            rowsDeleted++;
        }
    }
    return { success: true, rowsDeleted };
}

