function saveKKTP({ data }) { return saveData(SHEETS.KKTP, data); }
function deleteKKTPsByATPId({ atpId }) { return deleteDataByForeignKey(SHEETS.KKTP, 'atpId', atpId); }
function deleteKKTPsByTPId({ tpId }) {
    const atps = getATPsByTPId({ tpId });
    atps.forEach(atp => deleteKKTPsByATPId({ atpId: atp.id }));
