    case 'generateATP':
      prompt += `\n\nAnda adalah ahli dalam menyusun alur pembelajaran. Diberikan data TP dalam format JSON, urutkan TP tersebut ke dalam alur yang paling logis dan efektif untuk diajarkan.`;
      prompt += `\nData TP: ${JSON.stringify(params.tpData.tpGroups, null, 2)}`;
      prompt += `\nFormat output WAJIB berupa JSON array yang berisi HANYA indeks (dimulai dari 0) dari TP yang telah diurutkan. Contoh: [3, 0, 1, 4, 2]`;
      break;
    case 'generatePROTA':
      prompt += `\n\nAnda adalah ahli dalam alokasi waktu pembelajaran. Diberikan data ATP dan informasi bahwa ada ${params.jamPertemuan} Jam Pertemuan (JP) per minggu. Alokasikan JP untuk setiap TP secara proporsional.`;
      prompt += `\nData ATP: ${JSON.stringify(params.atpData.content, null, 2)}`;
      prompt += `\nFormat output WAJIB berupa JSON array dari objek dengan struktur: [{ index: number, alokasiWaktu: string (contoh: "4 JP") }]`;
      break;
    case 'generateKKTP':
      prompt += `\n\nAnda adalah ahli dalam penilaian dan evaluasi. Untuk setiap TP pada Semester ${params.semester} Kelas ${params.grade} berikut, buatkan 4 level kriteria (sangat mahir, mahir, cukup mahir, perlu bimbingan) dan tentukan satu target KKTP yang paling sesuai.`;
      const semesterContent = params.atpData.content.filter(row => row.semester === params.semester);
      prompt += `\nData TP: ${JSON.stringify(semesterContent, null, 2)}`;
      prompt += `\nFormat output WAJIB berupa JSON array dari objek dengan struktur: [{ index: number, kriteria: { sangatMahir: string, mahir: string, cukupMahir: string, perluBimbingan: string }, targetKktp: 'sangatMahir'|'mahir'|'cukupMahir'|'perluBimbingan' }]`;
      break;
    case 'generatePROSEM':
       prompt += `\n\nAnda adalah ahli kalender akademik. Buatkan Program Semester (PROSEM) untuk Semester ${params.semester} Kelas ${params.grade} berdasarkan data PROTA berikut. Distribusikan alokasi waktu JP ke dalam minggu-minggu efektif per bulan. Asumsikan bulan-bulan efektif untuk semester ${params.semester} adalah: ${params.semester === 'Ganjil' ? 'Juli (4 minggu), Agustus (5), September (4), Oktober (4), November (5), Desember (4)' : 'Januari (4), Februari (4), Maret (5), April (4), Mei (4), Juni (5)'}.`;
       const protaContent = params.protaData.content.filter(row => row.semester === params.semester);
       prompt += `\nData PROTA: ${JSON.stringify(protaContent, null, 2)}`;
       prompt += `\nFormat output WAJIB berupa objek JSON dengan struktur: { headers: [{ month: string, weeks: number }], content: [{ no: number|string, tujuanPembelajaran: string, alokasiWaktu: string, bulan: { "Juli": [string|null, ...] }, keterangan: string }] }`;
       break;
    default:
      throw new Error(`Tipe generasi '${generationType}' tidak dikenal.`);
  }

  const payload = { "contents": [{ "parts": [{ "text": prompt }] }], "generationConfig": { "temperature": 0.3, "topK": 1, "topP": 0.95, "maxOutputTokens": 8192 } };
  const options = { 'method': 'post', 'contentType': 'application/json', 'payload': JSON.stringify(payload), 'muteHttpExceptions': true };
  const response = UrlFetchApp.fetch(url, options);
  const responseCode = response.getResponseCode();
  const responseBody = response.getContentText();

  if (responseCode !== 200) {
    console.error("Error dari Gemini API:", responseBody);
    throw new Error(`Gagal menghubungi AI. Status: ${responseCode}. Detail: ${responseBody}`);
