      'generatePROTA': (p) => callGeminiAPI(p, 'generatePROTA'),
      'generateKKTP': (p) => callGeminiAPI(p, 'generateKKTP'),
      'generatePROSEM': (p) => callGeminiAPI(p, 'generatePROSEM'),
    };

    if (ACTION_MAP[action]) {
      const result = ACTION_MAP[action](params);
      return createSuccessResponse(result);
    } else {
      throw new Error(`Aksi tidak dikenal: '${action}'`);
    }

