function getSheet(sheetName) {
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  const sheet = ss.getSheetByName(sheetName);
  if (!sheet) throw new Error(`Sheet "${sheetName}" tidak ditemukan.`);
  return sheet;
}

function getSheetData(sheet) {
    const dataRange = sheet.getDataRange();
    if (dataRange.getNumRows() <= 1) return { headers: (dataRange.getNumRows() === 1 ? dataRange.getValues()[0] : []), rows: [] };
    const data = dataRange.getValues();
    const headers = data.shift(); // Baris pertama header
    return { headers, rows: data };
}

function rowsToObjects(headers, rows) {
  return rows.map(row => {
    let obj = {};
    headers.forEach((header, index) => {
      obj[header] = row[index];
    });
    return obj;
  });
}

function getAllDataFromSheet(sheetName) {
  const sheet = getSheet(sheetName);
  const { headers, rows } = getSheetData(sheet);
  if (rows.length === 0) return [];
  return rowsToObjects(headers, rows);
}

// Mencari index baris berdasarkan nilai kolom (misal: id)
function findRowIndex(sheet, headers, searchColumn, searchValue) {
  const columnIndex = headers.indexOf(searchColumn);
  if (columnIndex === -1) return -1;

  const lastRow = sheet.getLastRow();
  if (lastRow < 2) return -1;

  // Ambil hanya kolom yang dicari untuk mempercepat
  const data = sheet.getRange(2, columnIndex + 1, lastRow - 1, 1).getValues();
  for (let i = 0; i < data.length; i++) {
    if (String(data[i][0]) === String(searchValue)) {
      return i + 2; // +2 karena array mulai 0 dan ada header row
    }
  }
  return -1;
}

function objectToRowArray(headers, obj) {
  return headers.map(header => {
    const value = obj[header];
    if (typeof value === 'object' && value !== null) {
      return JSON.stringify(value);
    }
    return value !== undefined && value !== null ? value : "";
  });
}

