function callGeminiAPI(params, generationType) {
  const apiKey = PropertiesService.getScriptProperties().getProperty(GEMINI_API_KEY_PROPERTY);
  if (!apiKey) throw new Error("Kunci API Gemini belum diatur di Script Properties.");

  const model = params.model || 'gemini-2.5-flash';
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`;

  let prompt = "Anda adalah asisten ahli kurikulum untuk guru di madrasah tsanawiyah di Indonesia. Selalu berikan respons HANYA dalam format JSON yang valid tanpa markdown.";

  switch (generationType) {
    case 'generateTPs':
      prompt += `\n\nBuatkan Tujuan Pembelajaran (TP) untuk mapel ${params.subject} kelas ${params.grade} berdasarkan CP berikut:\n`;
      params.cpElements.forEach(el => { prompt += `- Elemen: ${el.element}\n- CP: ${el.cp}\n`; });
      prompt += `\nSusun TP ke dalam materi pokok dengan urutan: ${params.additionalNotes}.`;
      prompt += `\nOutput WAJIB JSON Array: [{ semester: 'Ganjil'|'Genap', materi: string, subMateriGroups: [{ subMateri: string, tps: string[] }] }]`;
      break;

    case 'generateATP':
      prompt += `\n\nUrutkan TP berikut agar menjadi alur pembelajaran yang logis.`;
      prompt += `\nData TP: ${JSON.stringify(params.tpData.tpGroups)}`;
      prompt += `\nOutput WAJIB JSON Array berisi indeks (0-based) urutan baru. Contoh: [3, 0, 1, 4, 2]`;
      break;

    case 'generatePROTA':
      prompt += `\n\nAlokasikan ${params.jamPertemuan} JP per minggu untuk ATP berikut secara proporsional.`;
      prompt += `\nData ATP: ${JSON.stringify(params.atpData.content)}`;
      prompt += `\nOutput WAJIB JSON Array: [{ index: number, alokasiWaktu: string (contoh: "4 JP") }]`;
      break;

    case 'generateKKTP':
      prompt += `\n\nBuat kriteria penilaian (4 level) dan target KKTP untuk TP Semester ${params.semester} Kelas ${params.grade} berikut.`;
      const semesterContent = params.atpData.content.filter(row => row.semester === params.semester);
      prompt += `\nData: ${JSON.stringify(semesterContent)}`;
      prompt += `\nOutput WAJIB JSON Array: [{ index: number, kriteria: { sangatMahir: string, mahir: string, cukupMahir: string, perluBimbingan: string }, targetKktp: 'sangatMahir'|'mahir'|'cukupMahir'|'perluBimbingan' }]`;
      break;

    case 'generatePROSEM':
       const bulanEfektif = params.semester === 'Ganjil' 
         ? 'Juli (4 minggu), Agustus (5), September (4), Oktober (4), November (5), Desember (4)' 
         : 'Januari (4), Februari (4), Maret (5), April (4), Mei (4), Juni (5)';

       prompt += `\n\nBuat PROSEM Semester ${params.semester} Kelas ${params.grade}. Bulan efektif: ${bulanEfektif}.`;
       const protaContent = params.protaData.content.filter(row => row.semester === params.semester);
       prompt += `\nData PROTA: ${JSON.stringify(protaContent)}`;
       prompt += `\nOutput WAJIB JSON Object: { headers: [{ month: string, weeks: number }], content: [{ no: number, tujuanPembelajaran: string, alokasiWaktu: string, bulan: { "NamaBulan": [string|null (isi JP), ...] }, keterangan: string }] }`;
       break;

    default:
      throw new Error(`Tipe generasi '${generationType}' tidak dikenal.`);
  }

  const payload = { 
    "contents": [{ "parts": [{ "text": prompt }] }],
    "generationConfig": { "temperature": 0.3, "topK": 1, "topP": 0.95, "maxOutputTokens": 8192 } 
  };

  const options = { 
    'method': 'post', 
    'contentType': 'application/json', 
    'payload': JSON.stringify(payload), 
    'muteHttpExceptions': true 
  };

  const response = UrlFetchApp.fetch(url, options);
  const responseCode = response.getResponseCode();
  const responseBody = response.getContentText();

  if (responseCode !== 200) {
    throw new Error(`Gagal menghubungi AI (Status ${responseCode}): ${responseBody}`);
  }

  const jsonResponse = JSON.parse(responseBody);
  const text = jsonResponse.candidates?.[0]?.content?.parts?.[0]?.text;

  if (!text) throw new Error("AI memberikan respons kosong atau terblokir.");

  return { text: text };
}

